function cellKey(cell: Cell): string {
  return `${cell[0]},${cell[1]}`;
}

function deadNeighborCandidates(liveCells: Cell[]): Cell[] {
  const liveKeys = new Set(liveCells.map(cellKey));
  const candidates = new Map<string, Cell>();
  for (const [x, y] of liveCells) {
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        if (dx === 0 && dy === 0) continue;
        const candidate: Cell = [x + dx, y + dy];
        const key = cellKey(candidate);
        if (!liveKeys.has(key)) candidates.set(key, candidate);
      }
    }
  }
  return [...candidates.values()];
}

export function nextGeneration(liveCells: Cell[]): Cell[] {
  const survivors = liveCells.filter((cell) => {
    const liveNeighborCount = countLiveNeighbors(cell, liveCells);
    return liveNeighborCount === 2 || liveNeighborCount === 3;
  });
  const births = deadNeighborCandidates(liveCells).filter(
    (cell) => countLiveNeighbors(cell, liveCells) === 3
  );
  return [...survivors, ...births];
}

